1	/**
2	 * decision-review clockwork engine.
3	 *
4	 * Two-pass engine:
5	 *
6	 * First run (plan status 'analyzing'):
7	 *   - Maps decisions to ChoiceQuestionSpec and scope items to BooleanQuestionSpec.
8	 *   - Creates an InputRequestDoc in spider/input-requests.
9	 *   - Blocks with 'patron-input' block type.
10	 *   - If no decisions and no scope items, completes immediately.
11	 *
12	 * Re-run (plan status 'reviewing'):
13	 *   - Reads the completed InputRequestDoc.
14	 *   - Reconciles answers back into the PlanDoc.
15	 *   - Yields a human-readable decisionSummary markdown string.
16	 */
17	
18	import { guild, generateId } from '@shardworks/nexus-core';
19	import type { EngineDesign, EngineRunContext, EngineRunResult } from '@shardworks/fabricator-apparatus';
20	import type { Book } from '@shardworks/stacks-apparatus';
21	import type { StacksApi } from '@shardworks/stacks-apparatus';
22	import type { ClerkApi } from '@shardworks/clerk-apparatus';
23	import type {
24	  InputRequestDoc,
25	  ChoiceQuestionSpec,
26	  BooleanQuestionSpec,
27	  AnswerValue,
28	  ChoiceAnswer,
29	} from '@shardworks/spider-apparatus';
30	import type { PlanDoc, Decision, DecisionAnalysis, ScopeItem } from '../types.ts';
31	
32	// ── Helpers ──────────────────────────────────────────────────────────
33	
34	function composeDetails(context?: string, rationale?: string): string | undefined {
35	  if (context && rationale) {
36	    return `${context}\n\nRecommendation rationale: ${rationale}`;
37	  }
38	  if (context) return context;
39	  if (rationale) return `Recommendation rationale: ${rationale}`;
40	  return undefined;
41	}
42	
43	const CONFIDENCE_TAGS: Record<string, string> = {
44	  low: 'low-confidence',
45	  medium: 'medium-confidence',
46	  high: 'high-confidence',
47	};
48	
49	const STAKES_TAGS: Record<string, string> = {
50	  low: 'low-stakes',
51	  high: 'high-stakes',
52	};
53	
54	const CATEGORY_TAGS: Record<string, string> = {
55	  product: 'product',
56	  api: 'api',
57	  implementation: 'implementation',
58	};
59	
60	const OBSERVABLE_TAGS: Record<string, string> = {
61	  true: 'observable',
62	  false: 'internal',
63	};
64	
65	function buildAnalysisTags(analysis: DecisionAnalysis | undefined): string[] | undefined {
66	  if (!analysis) return undefined;
67	
68	  const tags: string[] = [];
69	
70	  if (analysis.confidence !== undefined && CONFIDENCE_TAGS[analysis.confidence]) {
71	    tags.push(CONFIDENCE_TAGS[analysis.confidence]);
72	  }
73	  if (analysis.stakes !== undefined && STAKES_TAGS[analysis.stakes]) {
74	    tags.push(STAKES_TAGS[analysis.stakes]);
75	  }
76	  if (analysis.category !== undefined && CATEGORY_TAGS[analysis.category]) {
77	    tags.push(CATEGORY_TAGS[analysis.category]);
78	  }
79	  if (analysis.observable !== undefined && OBSERVABLE_TAGS[String(analysis.observable)]) {
80	    tags.push(OBSERVABLE_TAGS[String(analysis.observable)]);
81	  }
82	
83	  if (tags.length === 0) return undefined;
84	  return tags.sort();
85	}
86	
87	function buildDecisionSummary(decisions: Decision[], scope: ScopeItem[]): string {
88	  const parts: string[] = [];
89	
90	  if (decisions.length > 0) {
91	    parts.push('## Decisions');
92	    parts.push('');
93	    for (const decision of decisions) {
94	      parts.push(`### ${decision.id}: ${decision.question}`);
95	      const selectedKey = decision.selected ?? decision.recommendation;
96	      if (selectedKey && decision.options[selectedKey]) {
97	        parts.push(`**Selected:** ${decision.options[selectedKey]}`);
98	      } else if (selectedKey) {
99	        parts.push(`**Selected:** ${selectedKey}`);
100	      }
101	      if (decision.patronOverride) {
102	        parts.push(`**Patron override:** ${decision.patronOverride}`);
103	      }
104	      parts.push('');
105	    }
106	  }
107	
108	  if (scope.length > 0) {
109	    parts.push('## Scope');
110	    parts.push('');
111	    for (const item of scope) {
112	      const check = item.included ? '[x]' : '[ ]';
113	      const suffix = item.included ? '' : ' (excluded)';
114	      parts.push(`- ${check} ${item.id}: ${item.description}${suffix}`);
115	    }
116	  }
117	
118	  return parts.join('\n').trim();
119	}
120	
121	// ── Engine factory ───────────────────────────────────────────────────
122	
123	export function createDecisionReviewEngine(getPlansBook: () => Book<PlanDoc>): EngineDesign {
124	  return {
125	    id: 'astrolabe.decision-review',
126	
127	    async run(
128	      givens: Record<string, unknown>,
129	      context: EngineRunContext,
130	    ): Promise<EngineRunResult> {
131	      const planId = givens.planId as string;
132	      const book = getPlansBook();
133	
134	      const plan = await book.get(planId);
135	      if (!plan) {
136	        throw new Error(`Plan "${planId}" not found.`);
137	      }
138	
139	      // ── First run: status === 'analyzing' ─────────────────────────
140	
141	      if (plan.status === 'analyzing') {
142	        const decisions = plan.decisions ?? [];
143	        const scopeItems = plan.scope ?? [];
144	
145	        // Fast-path: no decisions and no scope
146	        if (decisions.length === 0 && scopeItems.length === 0) {
147	          await book.patch(planId, {
148	            status: 'writing',
149	            updatedAt: new Date().toISOString(),
150	          });
151	          return {
152	            status: 'completed',
153	            yields: { decisionSummary: '' },
154	          };
155	        }
156	
157	        // Build questions
158	        const questions: Record<string, ChoiceQuestionSpec | BooleanQuestionSpec> = {};
159	        const answers: Record<string, AnswerValue> = {};
160	
161	        for (const decision of decisions) {
162	          const tags = buildAnalysisTags(decision.analysis);
163	          const choiceSpec: ChoiceQuestionSpec = {
164	            type: 'choice',
165	            label: decision.question,
166	            details: composeDetails(decision.context, decision.rationale),
167	            options: decision.options,
168	            allowCustom: true,
169	            ...(tags ? { tags } : {}),
170	          };
171	          questions[decision.id] = choiceSpec;
172	
173	          if (decision.recommendation) {
174	            answers[decision.id] = { selected: decision.recommendation } as ChoiceAnswer;
175	          }
176	        }
177	
178	        for (const item of scopeItems) {
179	          const boolSpec: BooleanQuestionSpec = {
180	            type: 'boolean',
181	            label: item.description,
182	            details: item.rationale,
183	          };
184	          questions[`scope:${item.id}`] = boolSpec;
185	          answers[`scope:${item.id}`] = item.included;
186	        }
187	
188	        // Compose message
189	        let message: string;
190	        try {
191	          const clerk = guild().apparatus<ClerkApi>('clerk');
192	          const writ = await clerk.show(planId);
193	          const includedScope = scopeItems.filter(s => s.included).map(s => s.description);
194	          const scopeSummary = includedScope.length > 0
195	            ? `\n\nIn-scope items: ${includedScope.join(', ')}`
196	            : '';
197	          message = `Planning review for: ${writ.title} (codex: ${plan.codex})${scopeSummary}`;
198	        } catch {
199	          message = `Planning review for plan: ${planId} (codex: ${plan.codex})`;
200	        }
201	
202	        // Create InputRequestDoc
203	        const requestId = generateId('ir', 4);
204	        const now = new Date().toISOString();
205	        const inputRequest: InputRequestDoc = {
206	          id: requestId,
207	          rigId: context.rigId,
208	          engineId: context.engineId,
209	          status: 'pending',
210	          message,
211	          questions,
212	          answers,
213	          createdAt: now,
214	          updatedAt: now,
215	        };
216	
217	        const stacks = guild().apparatus<StacksApi>('stacks');
218	        const inputRequestsBook = stacks.book<InputRequestDoc>('spider', 'input-requests');
219	        await inputRequestsBook.put(inputRequest);
220	
221	        // Update plan status to 'reviewing'
222	        await book.patch(planId, {
223	          status: 'reviewing',
224	          updatedAt: now,
225	        });
226	
227	        return {
228	          status: 'blocked',
229	          blockType: 'patron-input',
230	          condition: { requestId },
231	        };
232	      }
233	
234	      // ── Re-run: status === 'reviewing' ────────────────────────────
235	
236	      if (plan.status === 'reviewing') {
237	        // Extract requestId from priorBlock or query book
238	        let requestId: string;
239	
240	        if (context.priorBlock?.condition) {
241	          const cond = context.priorBlock.condition as { requestId: string };
242	          requestId = cond.requestId;
243	        } else {
244	          // Fallback: query by rigId + engineId
245	          const stacks = guild().apparatus<StacksApi>('stacks');
246	          const inputRequestsBook = stacks.book<InputRequestDoc>('spider', 'input-requests');
247	          const found = await inputRequestsBook.find({
248	            where: [
249	              ['rigId', '=', context.rigId],
250	              ['engineId', '=', context.engineId],
251	            ],
252	            limit: 1,
253	          });
254	          if (found.length === 0) {
255	            throw new Error(
256	              `No InputRequestDoc found for rig "${context.rigId}" engine "${context.engineId}".`,
257	            );
258	          }
259	          requestId = found[0].id;
260	        }
261	
262	        const stacks = guild().apparatus<StacksApi>('stacks');
263	        const inputRequestsBook = stacks.book<InputRequestDoc>('spider', 'input-requests');
264	        const inputRequest = await inputRequestsBook.get(requestId);
265	        if (!inputRequest) {
266	          throw new Error(`InputRequestDoc "${requestId}" not found.`);
267	        }
268	
269	        // Reconcile answers back into the plan
270	        const decisions = (plan.decisions ?? []).map(d => ({ ...d }));
271	        const scopeItems = (plan.scope ?? []).map(s => ({ ...s }));
272	
273	        for (const [key, answer] of Object.entries(inputRequest.answers)) {
274	          if (key.startsWith('scope:')) {
275	            const scopeId = key.slice('scope:'.length);
276	            const item = scopeItems.find(s => s.id === scopeId);
277	            if (item) {
278	              item.included = answer as boolean;
279	            }
280	          } else {
281	            const decision = decisions.find(d => d.id === key);
282	            if (decision) {
283	              const choiceAnswer = answer as ChoiceAnswer;
284	              if ('selected' in choiceAnswer) {
285	                decision.selected = choiceAnswer.selected;
286	              } else if ('custom' in choiceAnswer) {
287	                decision.patronOverride = choiceAnswer.custom;
288	              }
289	            }
290	          }
291	        }
292	
293	        // ── Validate consistency ──────────────────────────────────
294	        const unresolved = decisions.filter(
295	          d => d.selected === undefined && d.patronOverride === undefined,
296	        );
297	        if (unresolved.length > 0) {
298	          const ids = unresolved.map(d => d.id).join(', ');
299	          throw new Error(`Unresolved decisions after patron review: ${ids}`);
300	        }
301	
302	        const decisionSummary = buildDecisionSummary(decisions, scopeItems);
303	
304	        const now = new Date().toISOString();
305	        await book.patch(planId, {
306	          decisions,
307	          scope: scopeItems,
308	          status: 'writing',
309	          updatedAt: now,
310	        });
311	
312	        return {
313	          status: 'completed',
314	          yields: { decisionSummary },
315	        };
316	      }
317	
318	      throw new Error(
319	        `decision-review: unexpected plan status "${plan.status}" for plan "${planId}". ` +
320	          `Expected 'analyzing' or 'reviewing'.`,
321	      );
322	    },
323	  };
324	}
